  // If en_full_cov is set, then en_intg_cov must also be set since it is a subset.
  bit en_intg_cov_loc;
  assign en_intg_cov_loc = en_full_cov | en_intg_cov;

  covergroup csrng_sfifo_cg @(posedge clk_i);
    option.name         = "csrng_sfifo_cg";
