    }

    // HW1 App
    cp_hw1_cmd_depth: coverpoint hw1_cmd_depth{
      illegal_bins more_than_depth = {3};
    }
    cp_hw1_genbits_depth: coverpoint hw1_genbits_depth;
    hw1_cmd_cross: cross cp_hw1_cmd_depth, hw1_cmd_vld, hw1_cmd_rdy;
